#include <vector>
using namespace std;

class Solution {
public:
    vector<int> maxPrice(int n, int capacity, vector<int>& weight, vector<int>& price) {
        vector<vector<int>> dp(n + 1, vector<int>(capacity + 1, 0));
        for (int i = 1; i <= n; ++i) {
            for (int c = 0; c <= capacity; ++c) {
                dp[i][c] = dp[i - 1][c];
                if (c >= weight[i - 1]) {
                    int candidate = dp[i - 1][c - weight[i - 1]] + price[i - 1];
                    if (candidate > dp[i][c]) {
                        dp[i][c] = candidate;
                    }
                }
            }
        }

        vector<int> picked(n, 0);
        int c = capacity;
        for (int i = n; i >= 1; --i) {
            if (c >= weight[i - 1] && dp[i][c] == dp[i - 1][c - weight[i - 1]] + price[i - 1] && dp[i][c] > dp[i - 1][c]) {
                picked[i - 1] = 1;
                c -= weight[i - 1];
            }
        }
        return picked;
    }
};
